// Shuffle an array (used to randomize the order each session)
export function shuffleQuotes(arr: Quote[]): Quote[] {
  const copy = [...arr];
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [copy[i], copy[j]] = [copy[j], copy[i]];
  }
  return copy;
}
